const allInputs = $input.all();

const yfInput = allInputs.find(i =>
  i.json.quoteResponse ||
  i.json.meta?.status === 200 ||
  Array.isArray(i.json.body)
) || allInputs[0];

const ethInput = allInputs.find(i =>
  i.json.body?.ethereum ||
  i.json.ethereum
) || allInputs[1];

const yfRaw = yfInput.json;
const quotes = yfRaw.quoteResponse?.result
             || yfRaw.body
             || (Array.isArray(yfRaw) ? yfRaw : []);
const yf = {};
quotes.forEach(q => {
  const sym = q.symbol || q.ticker || '';
  const price = q.regularMarketPrice?.raw ?? q.regularMarketPrice ?? 0;
  if (sym) yf[sym] = Number(price) || 0;
});

const usdsgd = yf['USDSGD=X'] || 1.35;
const phpsgd = yf['PHPSGD=X'] || 0.023;
const S = v => (v == null || isNaN(v) || !isFinite(v)) ? 0 : Number(v);

// ── Read ETH & PSE Prices from TradingView nodes ────────────────
let ethSGD = 0;
const tvPsePrices = {};

try {
  const tvEthData = $('TradingView ETHSGD').first().json;
  ethSGD = S(tvEthData.data?.[0]?.d?.[1]);
} catch (e) {
  // Fallback to CoinGecko input if TradingView fails
  const ethRaw = ethInput.json.body || ethInput.json;
  ethSGD = Number(ethRaw?.ethereum?.sgd) || Number(ethInput.json?.ethereum?.sgd) || 0;
}

try {
  const tvPseData = $('TradingView PSE').first().json;
  (tvPseData.data || []).forEach(item => {
    const name = item.d[0];
    const close = item.d[1];
    tvPsePrices[name] = S(close);
  });
} catch (e) {
  // Handled via fallback values in the loop below
}

// ── Current SG positions (C38U removed, names & costs matched to MooMoo console) ──
const pos = [
  {sym:'A17U.SI', n:'A17U',  qty:400,    cost:2.53,    c:'SGD'},
  {sym:'AJBU.SI', n:'AJBU',  qty:500,    cost:1.9562,  c:'SGD'}, // Name matched
  {sym:'BUOU.SI', n:'BUOU',  qty:1500,   cost:0.9398,  c:'SGD'}, // Cost updated
  {sym:'J69U.SI', n:'J69U',  qty:1000,   cost:2.1109,  c:'SGD'}, // Name matched, cost 2.1109
  {sym:'JYEU.SI', n:'JYEU',  qty:900,    cost:0.5898,  c:'SGD'},
  {sym:'ME8U.SI', n:'ME8U',  qty:200,    cost:1.93,    c:'SGD'},
  {sym:'NVDA',    n:'NVDA',  qty:3,      cost:173.73,  c:'USD'}, // Cost updated
  {sym:'O5RU.SI', n:'O5RU',  qty:500,    cost:1.2515,  c:'SGD'}, // Name matched, cost updated
  {sym:'TSLA',    n:'TSLA',  qty:0.3549, cost:318.683, c:'USD'}
];

let totVal = 0, totPL = 0;
const rows = [];
for (const p of pos) {
  const rawP = S(yf[p.sym]);
  const pr   = S(p.c === 'USD' ? rawP * usdsgd : rawP);
  const co   = S(p.c === 'USD' ? p.cost * usdsgd : p.cost);
  const val  = S(p.qty * pr);
  const cst  = S(p.qty * co);
  const pl   = S(val - cst);
  const pct  = cst > 0 ? S(pl / cst * 100) : 0;
  totVal += val; totPL += pl;
  rows.push({ n:p.n, val, pl, pct });
}

// ── ETH (Blended cost and qty updated, row push corrected) ──
const ethQty = 0.6338458;
const ethBlendedCost = 2526.13484;

const eV = S(ethQty * ethSGD);
const ePL = S(eV - ethQty * ethBlendedCost);
const ePct = S((ethSGD - ethBlendedCost) / ethBlendedCost * 100);

totVal += eV;
totPL  += ePL;

rows.push({ n:'ETH', price:ethSGD, currency:'SGD', qty:ethQty, cost:ethBlendedCost, val:eV, pl:ePL, pct:ePct, noP:false });


// ── Current PERA+ positions (Dynamic TV Prices & Fallback) ────────────────
const peraFallback = {
  'AREIT': 38.40,
  'CREIT': 3.50,
  'MBT':   63.00,
  'MREIT': 14.00,
  'RCR':   6.75
};

const peraPos = [
  {n:'AREIT', qty:1200, cost:40.6445},
  {n:'CREIT', qty:8000, cost:3.4038},
  {n:'MBT',   qty:430,  cost:67.6711},
  {n:'MREIT', qty:1900, cost:13.5704},
  {n:'RCR',   qty:4300, cost:6.79}
];
let peraTotVal = 0, peraTotPL = 0;
const peraRows = [];
for (const p of peraPos) {
  const pricePhp = tvPsePrices[p.n] || peraFallback[p.n] || 0;
  const val = S(p.qty * pricePhp);
  const cst = S(p.qty * p.cost);
  const pl  = S(val - cst);
  const pct = cst > 0 ? S(pl / cst * 100) : 0;
  peraTotVal += val; peraTotPL += pl;
  peraRows.push({ n:p.n, val, pl, pct });
}

// ── Load previous snapshot from n8n static data ────────────────
const workflowStaticData = $getWorkflowStaticData('global');
const prev = workflowStaticData.prevSnapshot || null;

// ── Week-on-week diff helpers ──────────────────────────────────
const wowVal = (cur, prv) => prv ? cur - prv : null;
const wowPct = (cur, prv) => prv && prv !== 0 ? ((cur - prv) / Math.abs(prv) * 100) : null;

const sgWow   = prev ? wowVal(totVal, prev.total_value) : null;
const peraWow = prev ? wowVal(peraTotVal, prev.pera_total_val) : null;

const rowsWithWow = rows.map(r => {
  const prevRow = prev?.rows?.find(p => p.n === r.n);
  return {
    ...r,
    prev_val: prevRow?.val || null,
    wow_val:  prevRow ? wowVal(r.val, prevRow.val) : null,
    wow_pct:  prevRow ? wowPct(r.val, prevRow.val) : null
  };
});

const peraRowsWithWow = peraRows.map(r => {
  const prevRow = prev?.peraRows?.find(p => p.n === r.n);
  return {
    ...r,
    prev_val: prevRow?.val || null,
    wow_val:  prevRow ? wowVal(r.val, prevRow.val) : null,
    wow_pct:  prevRow ? wowPct(r.val, prevRow.val) : null
  };
});

const allRows = [...rowsWithWow, ...peraRowsWithWow].filter(r => r.wow_val !== null);
const top3 = [...allRows].sort((a,b) => Math.abs(b.wow_val) - Math.abs(a.wow_val)).slice(0, 3);

// ── Save current as new snapshot for next week ─────────────────
workflowStaticData.prevSnapshot = {
  saved_at:       new Date().toISOString(),
  total_value:    Math.round(totVal * 100) / 100,
  total_pl:       Math.round(totPL * 100) / 100,
  pera_total_val: Math.round(peraTotVal * 100) / 100,
  pera_total_pl:  Math.round(peraTotPL * 100) / 100,
  rows:           rows.map(r => ({ n:r.n, val:r.val, pl:r.pl, pct:r.pct })),
  peraRows:       peraRows.map(r => ({ n:r.n, val:r.val, pl:r.pl, pct:r.pct }))
};

return [{ json: {
  rows: rowsWithWow,
  peraRows: peraRowsWithWow,
  top3,
  total_value:    Math.round(totVal * 100) / 100,
  total_pl:       Math.round(totPL * 100) / 100,
  pera_total_val: Math.round(peraTotVal * 100) / 100,
  pera_total_pl:  Math.round(peraTotPL * 100) / 100,
  sg_wow:         sgWow !== null ? Math.round(sgWow * 100) / 100 : null,
  pera_wow:       peraWow !== null ? Math.round(peraWow * 100) / 100 : null,
  usdsgd, phpsgd, eth_sgd: ethSGD,
  prev_saved_at:  prev?.saved_at || null,
  timestamp:      new Date().toISOString()
}}];

const d = $input.first().json;

// ── Randomised weekly lens ────────────────────────────────────
const lenses = [
  'Write from a risk management perspective — what threatened the portfolio this week and what needs protecting.',
  'Write from an income investor perspective — focus on dividend health, yield changes, and cash flow this week.',
  'Write from a growth perspective — which positions gained most and where is the upside heading into next week.',
  'Write from a capital preservation perspective — what held up, what eroded, and what needs defending.',
  'Write from a sector rotation perspective — where did money flow this week across SG REITs, PH stocks, US tech, and crypto.'
];

// ── Week number for lens rotation (changes every week) ────────
const weekNum = Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000));
const todayLens = lenses[weekNum % lenses.length];

// ── WoW strings ───────────────────────────────────────────────
const wowStr = d.sg_wow !== null
  ? (d.sg_wow >= 0 ? '+S$' : '-S$') + Math.abs(Math.round(d.sg_wow)) + ' vs last Saturday'
  : 'no prior snapshot';
const peraWowStr = d.pera_wow !== null
  ? (d.pera_wow >= 0 ? '+₱' : '-₱') + Math.abs(Math.round(d.pera_wow)) + ' vs last Saturday'
  : 'no prior snapshot';

// ── Top 3 movers summary ──────────────────────────────────────
const top3Str = d.top3 && d.top3.length
  ? 'Top 3 movers this week: ' + d.top3.map(r =>
      r.n + ' ' + (r.wow_val >= 0 ? '+' : '') + 'S$' + Math.round(r.wow_val)
    ).join(', ') + '. '
  : '';

const divStr = d.dividends && d.dividends.length
  ? '\nDividends Calendar:\n' + d.dividends.map(r =>
      `${r.n}: Ex-Date ${r.exDate}, Amount ${r.currency === 'SGD' ? 'S$' : '₱'}${r.amount.toFixed(4)}, Pay-Date ${r.payDate}`
    ).join('\n')
  : '';

const content = 'Return ONLY raw JSON, no markdown, no backticks. ' +
  'This is a WEEKLY portfolio digest for Bobby as of ' + d.timestamp + '. ' +
  'Weekly analysis lens: ' + todayLens + ' ' +
  'MooMoo SG: S$' + d.total_value + ' (P/L S$' + d.total_pl + ', week change: ' + wowStr + '). ' +
  'DragonFi PERA+: PHP' + d.pera_total_val + ' (P/L PHP' + d.pera_total_pl + ', week change: ' + peraWowStr + '). ' +
  'USDSGD: ' + d.usdsgd + ' PHPSGD: ' + d.phpsgd + divStr + ' ETH: S$' + d.eth_sgd + '. ' +
  top3Str +
  'All SG positions this week: ' + d.rows.map(r =>
    r.n + ' val S$' + Math.round(r.val) +
    (r.wow_val !== null ? ' wow:' + (r.wow_val >= 0 ? '+' : '') + 'S$' + Math.round(r.wow_val) : '') +
    ' ' + (r.pct >= 0 ? '+' : '') + r.pct.toFixed(1) + '%'
  ).join(', ') + '. ' +
  'All PERA+ positions this week: ' + d.peraRows.map(r =>
    r.n + ' val PHP' + Math.round(r.val) +
    (r.wow_val !== null ? ' wow:' + (r.wow_val >= 0 ? '+' : '') + 'PHP' + Math.round(r.wow_val) : '') +
    ' ' + (r.pct >= 0 ? '+' : '') + r.pct.toFixed(1) + '%'
  ).join(', ') + '. ' +
  'Context: Bobby is Singapore-based OFW investor. Income-first strategy. ' +
  'MooMoo SG: AJBU (Keppel DC Reit), A17U (CapLand Ascendas industrial/DC REIT), BUOU (Frasers Logistics REIT), J69U (suburban retail REIT), JYEU (Lendlease commercial REIT), ME8U (Mapletree Industrial Trust), O5RU (AIMS APAC industrial REIT), NVDA (tech growth), TSLA (growth), ETH (crypto growth/non-yielding). ' +
  'DragonFi PERA+: AREIT (Ayala Land REIT), CREIT (Citicore renewable energy), MBT (Metrobank), MREIT (Megaworld REIT), RCR (RL Commercial REIT). ' +
  'Strategy Context: Portfolio has a bimodal strategy: REITs & Banks (A17U, AJBU, BUOU, J69U, JYEU, ME8U, O5RU, AREIT, CREIT, MREIT, RCR, MBT) are long-term yield assets held for compound distributions — focus on dividend health, gearing, and distribution stability, and do NOT recommend panic-selling them on short-term price drops. US Equities (NVDA, TSLA) and Crypto (ETH) are tactical growth assets — recommend active capital protection triggers (stop-losses) or exit strategies here. ' +
  'Actionability constraint: Never give vague advice like "reassess positions". Always specify exact price-based actions or rebalancing ratios (e.g. "If ETH drops below S$2000, rotate into AJBU"). ' +
  'Return this JSON: {' +
  '"weekly_summary":"2 sentences max. Apply the weekly lens above. One line on combined portfolio week-on-week change, one line on what drove it. Punchy and fresh — do not sound like last week.",' +
  '"sg_commentary":"2 sentences. Apply the weekly lens. Top mover and biggest drag only. Skip flat positions.",' +
  '"pera_commentary":"2 sentences. Apply the weekly lens. PSE week in one line, one position to watch next week.",' +
  '"week_verdict":"one word: GOOD, MIXED, or TOUGH",' +
  '"next_week_watch":"2 sentences max. Apply the weekly lens. Most important thing to act on or monitor next week across both portfolios."' +
  '}';

return [{ json: { ...d, claudeContent: content } }];

const d = $('Calculate Dividends').first().json;
const rawResp = $input.first().json;

let ai;
try {
  const text  = rawResp.choices[0].message.content;
  const clean = text.replace(/```json|```/g, '').trim();
  ai = JSON.parse(clean);
} catch(e) {
  ai = {
    weekly_summary:   'Weekly digest generated. AI analysis unavailable this run.',
    sg_commentary:    '',
    pera_commentary:  '',
    week_verdict:     'MIXED',
    next_week_watch:  ''
  };
}

const ts = new Date(d.timestamp).toLocaleString('en-SG', {
  timeZone:'Asia/Singapore', weekday:'long', day:'2-digit', month:'short', year:'numeric'
});
const prevTs = d.prev_saved_at ? new Date(d.prev_saved_at).toLocaleString('en-SG', {
  timeZone:'Asia/Singapore', weekday:'long', day:'2-digit', month:'short', year:'numeric'
}) : 'No prior snapshot';

const plColor  = v => v >= 0 ? '#00c896' : '#e74c3c';
const fmtSgd   = v => v == null ? 'N/A' : (v >= 0 ? '+S$' : '-S$') + Math.abs(Math.round(v)).toLocaleString();
const fmtPhp   = v => v == null ? 'N/A' : (v >= 0 ? '+₱' : '-₱') + Math.abs(Math.round(v)).toLocaleString();
const fmtPct   = v => v == null ? '' : (v >= 0 ? '+' : '') + v.toFixed(1) + '%';

const verdictColor = {'GOOD':'#00c896','MIXED':'#f5a623','TOUGH':'#e74c3c'}[ai.week_verdict] || '#3d9be9';

// ── SG comparison rows ─────────────────────────────────────────
const sgRows = d.rows.map(r => {
  const wowColor = r.wow_val === null ? '#6b8599' : r.wow_val >= 0 ? '#00c896' : '#e74c3c';
  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:12px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:12px 8px">S$${Math.round(r.prev_val || 0).toLocaleString()}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#c8d8e8;padding:12px 8px">S$${Math.round(r.val).toLocaleString()}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:${wowColor};padding:12px 8px">${r.wow_val !== null ? fmtSgd(r.wow_val) : '—'}</td>
    <td style="font-family:'Space Mono',monospace;font-size:11px;color:${wowColor};padding:12px 8px">${r.wow_pct !== null ? fmtPct(r.wow_pct) : '—'}</td>
  </tr>`;
}).join('');

// ── PERA+ comparison rows ──────────────────────────────────────
const peraRows = d.peraRows.map(r => {
  const wowColor = r.wow_val === null ? '#6b8599' : r.wow_val >= 0 ? '#00c896' : '#e74c3c';
  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:12px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:12px 8px">₱${Math.round(r.prev_val || 0).toLocaleString()}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#c8d8e8;padding:12px 8px">₱${Math.round(r.val).toLocaleString()}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:${wowColor};padding:12px 8px">${r.wow_val !== null ? fmtPhp(r.wow_val) : '—'}</td>
    <td style="font-family:'Space Mono',monospace;font-size:11px;color:${wowColor};padding:12px 8px">${r.wow_pct !== null ? fmtPct(r.wow_pct) : '—'}</td>
  </tr>`;
}).join('');

// ── Dividends Section ──────────────────────────────────────────
const divRows = (d.dividends || []).map(r => {
  const amtStr = r.currency === 'SGD' ? 'S$' + r.amount.toFixed(4) : '₱' + r.amount.toFixed(4);
  const exD = new Date(r.exDate);
  const payD = new Date(r.payDate);
  const today = new Date();

  let status = 'Paid';
  let color = '#6db8a0';

  const todayMidnight = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const exMidnight = new Date(exD.getFullYear(), exD.getMonth(), exD.getDate());
  const payMidnight = new Date(payD.getFullYear(), payD.getMonth(), payD.getDate());

  if (todayMidnight < exMidnight) {
    status = 'Upcoming';
    color = '#3d9be9';
  } else if (todayMidnight >= exMidnight && todayMidnight < payMidnight) {
    status = 'Pending Pay';
    color = '#f5a623';
  }

  const statusHtml = `<span style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.08em;padding:3px 9px;border-radius:20px;background:${color}22;color:${color};border:1px solid ${color}44">${status}</span>`;

  const fmtDate = dateObj => dateObj.toLocaleDateString('en-SG', {
    day: '2-digit', month: 'short', year: 'numeric'
  });

  return `<tr>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:13px;color:#c8d8e8;padding:12px 12px">${r.n}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:12px 8px">${fmtDate(exD)}</td>
    <td style="font-family:'Space Mono',monospace;font-weight:700;font-size:12px;color:#00c896;padding:12px 8px">${amtStr}</td>
    <td style="font-family:'Space Mono',monospace;font-size:12px;color:#6b8599;padding:12px 8px">${fmtDate(payD)}</td>
    <td style="padding:12px 8px">${statusHtml}</td>
  </tr>`;
}).join('');

const divTableHtml = `
<div style="margin-bottom:28px">
  <div class="label">📅 Dividends Calendar (Declared / Recent)</div>
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;overflow:hidden">
    <table>
      <thead><tr>
        <th>Asset</th><th>Ex-Date</th><th>Amount</th><th>Payment Date</th><th>Status</th>
      </tr></thead>
      <tbody>${divRows}</tbody>
    </table>
  </div>
</div>
`;

// ── Top 3 movers ───────────────────────────────────────────────
const top3Html = d.top3.map(r => {
  const isPhp  = d.peraRows.some(p => p.n === r.n);
  const arrow  = r.wow_val >= 0 ? '▲' : '▼';
  const color  = r.wow_val >= 0 ? '#00c896' : '#e74c3c';
  const change = isPhp ? fmtPhp(r.wow_val) : fmtSgd(r.wow_val);
  return `<div style="display:flex;justify-content:space-between;align-items:center;padding:12px 16px;border-bottom:1px solid #1a2636">
    <span style="font-family:'Space Mono',monospace;font-weight:700;color:#c8d8e8">${r.n}</span>
    <span style="font-family:'Space Mono',monospace;font-size:13px;color:${color}">${arrow} ${change} (${fmtPct(r.wow_pct)})</span>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Bobby Portfolio — Weekly Digest</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet">
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{background:#0a0e14;color:#c8d8e8;font-family:'DM Sans',sans-serif;min-height:100vh}
body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.025) 2px,rgba(0,0,0,0.025) 4px);pointer-events:none;z-index:0}
.wrap{max-width:980px;margin:0 auto;padding:36px 20px;position:relative;z-index:1}
table{width:100%;border-collapse:collapse}
thead th{font-family:'Space Mono',monospace;font-size:9px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;padding:9px 12px;text-align:left;border-bottom:1px solid #1a2636}
tbody tr{border-bottom:1px solid rgba(26,38,54,0.6);transition:background 0.15s}
tbody tr:hover{background:#111c28}
.label{font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.15em;color:#3d5a72;text-transform:uppercase;margin-bottom:12px}
a{color:#3d9be9;font-family:'Space Mono',monospace;font-size:11px;text-decoration:none}
a:hover{text-decoration:underline}
</style>
</head>
<body>
<div class="wrap">

<div style="display:flex;justify-content:space-between;align-items:flex-start;border-bottom:1px solid #1a2636;padding-bottom:24px;margin-bottom:32px;flex-wrap:wrap;gap:12px">
  <div>
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.18em;color:#3d5a72;text-transform:uppercase;margin-bottom:8px">&#128200; Weekly Portfolio Digest</div>
    <div style="font-family:'Space Mono',monospace;font-size:22px;font-weight:700;color:#c8d8e8">Bobby Dionido &nbsp;<span style="font-size:14px;padding:3px 12px;border-radius:20px;background:${verdictColor}22;color:${verdictColor};border:1px solid ${verdictColor}44">${ai.week_verdict}</span></div>
  </div>
  <div style="text-align:right">
    <div style="font-family:'Space Mono',monospace;font-size:10px;color:#3d5a72">Week ending ${ts}</div>
    <div style="font-family:'Space Mono',monospace;font-size:10px;color:#3d5a72;margin-top:4px">vs ${prevTs}</div>
    <div style="margin-top:8px"><a href="/">&#8592; Daily Dashboard</a></div>
  </div>
</div>

<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-bottom:28px">
  <div style="background:#111820;border:1px solid #1a2636;border-radius:8px;padding:22px">
    <div style="font-family:'Space Mono',monospace;font-size:10px;letter-spacing:0.13em;color:#3d5a72;text-transform:uppercase;margin-bottom:10px">MooMoo SG</div>
    <div style="font-family:'Space Mono',monospace;font-size:22px;font-weight:700;color:#3d9be9">S$${Math.round(d.total_value).toLocaleString()}</div>
