      const result = data.chart.result[0];
      const divEvents = result.events?.dividends;
      if (divEvents) {
        const timestamps = Object.keys(divEvents).map(Number).sort((a,b) => b - a);
        if (timestamps.length > 0) {
          const latestTs = timestamps[0];
          const event = divEvents[latestTs];
          const exDateObj = new Date(latestTs * 1000);
          const exDateStr = exDateObj.toISOString().split('T')[0];

          // Estimate payment date as ex-date + 33 days
          const payDateObj = new Date(exDateObj.getTime() + 33 * 24 * 60 * 60 * 1000);
          const payDateStr = payDateObj.toISOString().split('T')[0];

          liveDividends.push({
            symbol: sym,
            n: sym.split('.')[0],
            exDate: exDateStr,
            amount: event.amount,
            currency: 'SGD',
            payDate: payDateStr
